args.cypher:
// Check Entity relationships more carefully
MATCH (sm:Submodel {id: 'urn:submodel:hall4:facilityinformation'})-[:HAS_ELEMENT]->(e1:Entity)
RETURN e1.idShort, labels(e1)

// Check what elements are directly in the submodel
MATCH (sm:Submodel {id: 'urn:submodel:hall4:facilityinformation'})-[:HAS_ELEMENT]->(el)
RETURN el.idShort, labels(el) LIMIT 20

// List all submodels of Hall 4
MATCH (aas:AssetAdministrationShell {idShort: 'Hall4'})-[:HAS_SUBMODEL]->(sm:Submodel)
RETURN sm.idShort, sm.id

// Check the HierarchicalStructures submodel for entity tree
MATCH (sm:Submodel {id: 'urn:submodel:hall4:hierarchicalstructures'})-[:HAS_ELEMENT*]->(el)
RETURN el.idShort, labels(el), el.value AS val

// Check the MiR100 nameplate
MATCH (sm:Submodel {id: 'urn:submodel:mir100:type:nameplate'})-[:HAS_ELEMENT*]->(p:Property)
RETURN p.idShort, p.value, p.valueType

// Check for File elements in the HandoverDocumentation submodel
MATCH (sm:Submodel {id: 'urn:submodel:mir100:type:handoverdocumentation'})-[:HAS_ELEMENT*]->(f:File)
RETURN f.idShort, f.value, f.contentType

MATCH (asset:Asset)
WHERE asset.globalAssetId = $ga OR EXISTS {
  MATCH (asset)-[:HAS_SPECIFIC_ASSET_ID]->(sa:SpecificAssetId)
  WHERE sa.value = $ga OR sa.name = $ga
}
RETURN asset.globalAssetId, asset.assetKind, [ (asset)-[:HAS_SPECIFIC_ASSET_ID]->(sa) RETURN sa.name AS name, sa.value AS value ] AS specificIds
